503: // sendExpire sends alerts to expire all previously firing alerts in the provided state transitions.
504: func (a *alertRule) expireAndSend(ctx context.Context, states []state.StateTransition) {
505: 	expiredAlerts := state.FromAlertsStateToStoppedAlert(states, a.appURL, a.clock, a.featureToggles)
506: 	if len(expiredAlerts.PostableAlerts) > 0 {
507: 		a.sender.Send(ctx, a.key.AlertRuleKey, expiredAlerts)
508: 	}
