126: func EvaluateAlert(queryResponse *backend.QueryDataResponse, condition models.Condition, now time.Time) Results {
127: 	execResults := queryDataResponseToExecutionResults(condition, queryResponse)
128: 	return evaluateExecutionResult(execResults, now)
