232: func (d *AlertsRouter) alertmanagersFromDatasources(orgID int64) ([]ExternalAMcfg, error) {
233: 	// We might have alertmanager datasources that are acting as external
234: 	// alertmanager, let's fetch them.
235: 	query := &datasources.GetDataSourcesByTypeQuery{
236: 		OrgID: orgID,
237: 		Type:  datasources.DS_ALERTMANAGER,
238: 	}
239: 	ctx, cancel := context.WithTimeout(context.Background(), time.Second*5)
240: 	defer cancel()
241: 	dataSources, err := d.datasourceService.GetDataSourcesByType(ctx, query)
242: 	if err != nil {
243: 		return nil, fmt.Errorf("failed to fetch datasources for org: %w", err)
244: 	}
245: 
246: 	alertmanagers := make([]ExternalAMcfg, 0, len(dataSources))
247: 
248: 	for _, ds := range dataSources {
249: 		if !ds.JsonData.Get(definitions.HandleGrafanaManagedAlerts).MustBool(false) {
250: 			continue
251: 		}
252: 		amURL, err := d.buildExternalURL(ds)
253: 		if err != nil {
254: 			d.logger.Error("Failed to build external alertmanager URL",
255: 				"org", ds.OrgID,
256: 				"uid", ds.UID,
257: 				"error", err)
258: 			continue
259: 		}
260: 		ctx, cancel := context.WithTimeout(context.Background(), time.Second*10)
261: 		headers, err := d.datasourceService.CustomHeaders(ctx, ds)
262: 		cancel()
263: 		if err != nil {
264: 			d.logger.Error("Failed to get headers for external alertmanager",
265: 				"org", ds.OrgID,
266: 				"uid", ds.UID,
267: 				"error", err)
268: 			continue
269: 		}
270: 
271: 		alertmanagers = append(alertmanagers, ExternalAMcfg{
272: 			URL:     amURL,
273: 			Headers: headers,
274: 		})
275: 	}
276: 
277: 	return alertmanagers, nil
278: }
