280: func (d *AlertsRouter) buildExternalURL(ds *datasources.DataSource) (string, error) {
281: 	// We re-use the same parsing logic as the datasource to make sure it matches whatever output the user received
282: 	// when doing the healthcheck.
283: 	parsed, err := datasource.ValidateURL(datasources.DS_ALERTMANAGER, ds.URL)
284: 	if err != nil {
285: 		return "", fmt.Errorf("failed to parse alertmanager datasource url: %w", err)
286: 	}
287: 
288: 	// If this is a Mimir or Cortex implementation, the Alert API is under a different path than config API
289: 	if ds.JsonData != nil {
290: 		impl := ds.JsonData.Get("implementation").MustString("")
291: 		switch impl {
292: 		case "mimir", "cortex":
293: 			if parsed.Path == "" {
294: 				parsed.Path = "/"
295: 			}
296: 			lastSegment := path.Base(parsed.Path)
297: 			if lastSegment != "alertmanager" {
298: 				parsed = parsed.JoinPath("/alertmanager")
299: 			}
300: 		default:
301: 		}
302: 	}
303: 
304: 	// If basic auth is enabled we need to build the url with basic auth baked in.
305: 	if ds.BasicAuth {
306: 		password := d.secretService.GetDecryptedValue(context.Background(), ds.SecureJsonData, "basicAuthPassword", "")
307: 		if password == "" {
308: 			return "", fmt.Errorf("basic auth enabled but no password set")
309: 		}
310: 		parsed.User = url.UserPassword(ds.BasicAuthUser, password)
311: 	}
312: 
313: 	return parsed.String(), nil
314: }
